import numpy as np
import matplotlib.pyplot as plt

def vn_entropy(rho):
    eig = np.linalg.eigvalsh(rho)
    eig = eig[eig > 1e-15]
    return -np.sum(eig * np.log2(eig)) if len(eig) > 0 else 0

def product_state_entropy(n):
    # Product state: S = 0 for any bipartition
    return 0

def random_state_entropy(n):
    # Random pure state: S ≈ n/2 - 1/(2 ln 2) (Page curve)
    if n <= 1:
        return 0
    # Half-system entropy for random state
    k = n // 2
    return k - (2**k - 1) / (2 * np.log(2) * 2**n)

print("Entropy Scaling Analysis")
print("="*40)
for n in [2, 4, 6, 8]:
    print(f"n={n}: Product S=0, Random S≈{random_state_entropy(n):.2f}")
